return

script.text:
      /* <flatten type="Javascript"> */
function activeForm$AdjustValue(f) {
  f.add_onResponseComplete(on$Form$AdjustValue$ResponseComplete);
  f.$a = {
    nguyen_gia: '[nguyen_gia]:=[nguyen_gia_nt]*[ty_gia]', gt_da_kh: '[gt_da_kh]:=[gt_da_kh_nt]*[ty_gia]',
    gt_cl: '[gt_cl]:=[gt_cl_nt]*[ty_gia]', gt_kh_ky: '[gt_kh_ky]:=[gt_kh_ky_nt]*[ty_gia]',
    y_gt_kh_ky: '[gt_kh_ky]:=[gt_cl]/[so_ky_kh]', y_gt_kh_ky_nt: '[gt_kh_ky_nt]:=[gt_cl_nt]/[so_ky_kh]',
    y_gt_cl: '[gt_cl]:=[nguyen_gia] - [gt_da_kh]', y_gt_cl_nt: '[gt_cl_nt]:=[nguyen_gia_nt] - [gt_da_kh_nt]'
  };
  setForm$AdjustValueDefaultValue(f);
}
function closeForm$AdjustValue(f) {try {f.remove_onResponseComplete(on$Form$AdjustValue$ResponseComplete);} catch (ex) {}}
function onChange$ItemCode(o) {o.parentForm.request('ItemCode', 'ItemCode', ['so_the_ts'], o);}
function onChange$AdjustType(o) {o.parentForm.request('AdjustType', 'AdjustType', [['action', 'String', o.parentForm._action], 'so_the_ts', 'ngay_ct', 'ma_nv', 'ma_tg_ts', 'nam', 'ky', 'so_ky_kh', 'gt_cl', 'gt_cl_nt'], o);}
function onChangeCurrency(f) {
  var v = (f._baseCurrency.toUpperCase() == f.getItemValue('ma_nt').toUpperCase());
  var a = ['nguyen_gia, gt_da_kh, gt_cl, gt_kh_ky, gt_kh_ky0', 'nguyen_gia_nt, gt_da_kh_nt, gt_cl_nt, gt_kh_ky_nt, gt_kh_ky0_nt'];
  var b = a[0].split(','), c = a[1].split(',');
  for (var i = 0; i < b.length; i++) {
    var n1 = $func.trim(b[i]), n2 = $func.trim(c[i]);
    var c1 = $get('idf_' + n1), c2 = $get('idf_' + n2), t1 = f.getItem(n1), t2 = f.getItem(n2);
    var format, h = t2._controlBehavior, changed = v;
    if (v) {
      if (!c2._saveHeader) c2._saveHeader = c2.innerHTML;
      if (!t2._saveDataFormatString) t2._saveDataFormatString = t2.field.DataFormatString;
      c2.innerHTML = c1.innerHTML;
      format = t1.field.DataFormatString;
    }
    else if (c2._saveHeader) {
      c2.innerHTML = c2._saveHeader;
      format = t2._saveDataFormatString;
      changed = true;
    }
    if (changed) {
      t2.field.DataFormatString = format;
      h.set_format(format);
      var n = $func.scaleLength(format);
      h._set_number($func.round(h._get_number(), n));
      $common.setVisible(c1.parentNode, !v);
      $common.setVisible(t1.parentNode, !v);
      f.getItem('ty_gia').disabled = v;
    }
  }
}
function onChange$FormItem$(o) {
  var f = o.parentForm, name = o.field.Name;
  switch (name) {
    case 'ty_gia':
      f.executeExpression([f.$a.nguyen_gia, f.$a.gt_da_kh, f.$a.gt_cl, f.$a.gt_kh_ky]);
      on$Form$Request(f);
      break;
    case 'nguyen_gia_nt':
      f.executeExpression([f.$a.nguyen_gia, f.$a.y_gt_cl_nt, f.$a.y_gt_cl]);
      f.live(f.getItem('nguyen_gia'));
      on$Form$Request(f);
      break;
    case 'nguyen_gia':
      f.executeExpression([f.$a.y_gt_cl]);
      on$Form$Request(f);
      break;
    case 'gt_da_kh_nt':
      f.executeExpression([f.$a.gt_da_kh, f.$a.y_gt_cl_nt, f.$a.y_gt_cl]);
      f.live(f.getItem('gt_da_kh'));
      on$Form$Request(f);
      break;
    case 'gt_da_kh':
      f.executeExpression([f.$a.y_gt_cl]);
      on$Form$Request(f);
      break;
    case 'gt_cl_nt':
      f.executeExpression([f.$a.gt_cl]);
      f.live(f.getItem('gt_cl'));
      on$Form$Request(f);
      break;
    case 'gt_kh_ky_nt':
      f.executeExpression([f.$a.gt_kh_ky]);
      on$AdjustValue$Request(f)
      break;
    case 'gt_kh_ky':
      f.executeExpression(['[gt_kh_ky0]:=[loai_tg_ts]==1?[tang_giam]+[gt_kh_ky]:[tang_giam] - [gt_kh_ky]']);
      break;
    case 'ma_nv':
    case 'ky':
    case 'nam':
      on$Form$Request(f);
      break;
    case 'so_ky_kh':
      if (f.getItemValue('so_ky_kh') > 0) f.request('FormRequest', 'AdjustPeriod', [['action', 'String', f._action], 'so_the_ts', 'ngay_ct', 'ma_nv', 'ma_tg_ts', 'nam', 'ky', 'so_ky_kh', 'gt_cl', 'gt_cl_nt']);
      break;
    default:
      break;
  }
}
function on$Form$Request(f) {f.request('FormRequest', 'FormRequest', [['action', 'String', f._action], 'so_the_ts', 'ngay_ct', 'ma_nv', 'ma_tg_ts', 'nam', 'ky', ['so_ky_kh', 'Decimal', 0], 'gt_cl', 'gt_cl_nt']);}
function on$AdjustValue$Request(f) {f.request('FormRequest', 'AdjustValue', [['action', 'String', f._action], 'so_the_ts', 'ngay_ct', 'ma_nv', 'ma_tg_ts', 'nam', 'ky', 'so_ky_kh', 'gt_cl', 'gt_cl_nt']);}
function on$Form$AdjustValue$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      onChangeCurrency(f);
      if (f._action == 'Edit' || f._action == 'View') refreh$Form$AdjustValue(f);
      break;
    case 'Scattering':
      setForm$AdjustValueDefaultValue(f);
      if (f._action == 'Edit' || f._action == 'View') refreh$Form$AdjustValue(f);
      break;
    case 'ItemCode':
      var c1 = result[0].Value, c2 = f.getItemValue('ma_nt');
      if (c1 != c2) {
        f.setItemControlBehavior('ma_nt', result[0].Value, result[1].Value, true);
        onChangeCurrency(f);
      }
      f.setItemValue('ty_gia', result[2].Value);
      break;
    case 'AdjustType':
      f.setItemValue('loai_tg_ts', result[0].Value);
      f.setItemValue('so_ky_kh', result[1].Value);
      f.setItemValue('tang_giam', result[2].Value);
      f.setItemValue('tang_giam_nt', result[3].Value);
      calc$Form$AdjustValue(f);
      refreh$Form$AdjustValue(f);
      break;
    case 'AdjustValue':
      f.setItemValue('so_ky_kh', result[0].Value);
      f.setItemValue('tang_giam', result[1].Value);
      f.setItemValue('tang_giam_nt', result[2].Value);
      refreh$Form$AdjustValue(f);
      f.live(f.getItem((f._baseCurrency.toUpperCase() == f.getItemValue('ma_nt').toUpperCase()) ? 'so_ky_kh' : 'gt_kh_ky'));
      break;
    case 'AdjustPeriod':
      f.setItemValue('gt_kh_ky0', result[3].Value);
      f.setItemValue('gt_kh_ky0_nt', result[4].Value);
      f.setItemValue('gt_kh_ky', result[5].Value);
      f.setItemValue('gt_kh_ky_nt', result[6].Value);
      f.live(f.getItem('gt_kh_ky_nt'));
      break;
    case 'FormRequest':
      f.setItemValue('so_ky_kh', result[0].Value);
      f.setItemValue('tang_giam', result[1].Value);
      f.setItemValue('tang_giam_nt', result[2].Value);
      calc$Form$AdjustValue(f);
      refreh$Form$AdjustValue(f);
      f.live(f.getItem('gt_kh_ky_nt'));
      f.live(f.getItem('so_ky_kh'));
      break;
    default:
      break;
  }
}
function setForm$AdjustValueDefaultValue(f) {
  if (f._action == 'New') {
    var d = new Date();
    f.setItemValue('ngay_ct', d);
    f.getItem('nam').value = d.getFullYear();
    f.getItem('ky').value = d.getMonth() + 1;
  }
  else if (f._action == 'Edit') {
    f._setReadOnly(f.getItem('so_the_ts'), true);
    f._setReadOnly(f.getItem('ma_nv'), true);
    f._setReadOnly(f.getItem('ma_tg_ts'), true);
    f._setReadOnly(f.getItem('ngay_ct'), true);
    try {f.getItem('nguyen_gia_nt').focus();} catch (ex) {}
  }
  f.getItem('ky').disabled = f.getItem('nam').disabled = f.getItem('ngay_ct').disabled = (f._action == 'Edit');
}
function calc$Form$AdjustValue(f) {
  var v = f.getItemValue('so_ky_kh');
  if (v == 0) {
      f.setItemValue('gt_kh_ky', 0);
      f.setItemValue('gt_kh_ky_nt', 0);
  } else f.executeExpression([f.$a.y_gt_kh_ky, f.$a.y_gt_kh_ky_nt]);
}
function refreh$Form$AdjustValue(f) {
  if (f.getItemValue('loai_tg_ts') == 1) f.executeExpression(['[gt_kh_ky0]:=[tang_giam]+[gt_kh_ky]', '[gt_kh_ky0_nt]:=[tang_giam_nt]+[gt_kh_ky_nt]']);
    else f.executeExpression(['[gt_kh_ky0]:=[tang_giam] - [gt_kh_ky]', '[gt_kh_ky0_nt]:=[tang_giam_nt] - [gt_kh_ky_nt]']);
}
/* </flatten> */
